using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking Change 1: Default discriminator property renamed from
            // "Discriminator" to "$type". Existing documents use the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking Change 2: HasIndex now throws for the Cosmos provider.
            // Removed: entity.HasIndex(b => b.Name);

            // Breaking Change 3: The Cosmos "id" property value changed from
            // "{Discriminator}|{Key}" to just "{Key}". Existing documents
            // store ids like "Blog|1", so we apply a converter to preserve
            // the old format while keeping Blog.Id as the logical key.
            entity.Property(b => b.Id)
                .HasConversion(
                    v => "Blog|" + v,
                    v => v.StartsWith("Blog|") ? v.Substring("Blog|".Length) : v);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

